if (!Array.isArray(msg.email?.attachments)) {
    msg.automationError = {
        class: 'configuration',
        message: 'Der IMAP-Eingang hat keine Attachment-Daten geliefert. Die Option Attachments muss aktiviert sein.',
        candidate: null,
        correlationId: String(msg._msgid || ''),
        occurredAt: new Date().toISOString()
    };
