const attachments = Array.isArray(msg.email?.attachments) ? msg.email.attachments : [];
const candidates = [];
const preparationErrors = [];

function asBuffer(content) {
    if (Buffer.isBuffer(content)) return Buffer.from(content);
    if (content && content.type === 'Buffer' && Array.isArray(content.data)) return Buffer.from(content.data);
    if (typeof content !== 'string') return null;
    const compact = content.replace(/\s+/g, '');
    if (!compact || compact.length % 4 !== 0 || !/^[A-Za-z0-9+/]*={0,2}$/.test(compact)) return null;
