    if (buffer.length >= 3 && buffer[0] === 0xef && buffer[1] === 0xbb && buffer[2] === 0xbf) start = 3;
    while (start < buffer.length && [0x09, 0x0a, 0x0d, 0x20].includes(buffer[start])) start += 1;
