    const byteXml = looksLikeXml(content);
    const bytePdf = content.subarray(0, 5).toString('ascii') === '%PDF-';
    if (!extensionCandidate && !mimeCandidate && !byteXml && !bytePdf) continue;
    const kind = byteXml || lowerName.endsWith('.xml') || contentType.includes('xml') ? 'xml' : 'pdf';
    if (candidates.some((candidate) => candidate.content.length === content.length && candidate.content.equals(content))) continue;
    candidates.push({ filename, contentType: kind === 'xml' ? 'application/xml' : 'application/pdf', kind, content, originalIndex: index });
