    return [null, msg];
}
return [msg, null];

const state = msg.automation;
const candidate = state?.candidates?.[state.candidateIndex];
const apiUrl = String(env.get('EINVOICE_API_URL') || 'http://127.0.0.1:8080/api/report/pdf').trim();
const apiToken = String(env.get('EINVOICE_API_TOKEN') || '');

function configurationError(message) {
    msg.automationError = { class: 'configuration', message, candidate: candidate?.filename || null, correlationId: state?.correlationId || null, occurredAt: new Date().toISOString() };
    delete msg.payload;
    delete msg.headers;
    delete msg.requestTimeout;
    delete msg.followRedirects;
    return [null, msg];
}

if (!candidate) return configurationError('Interner Flowzustand enthält keinen aktuellen Anhang.');
