const apiPort = apiUrlMatch?.[2] ? Number(apiUrlMatch[2]) : 80;
if (!apiUrlMatch || !Number.isInteger(apiPort) || apiPort < 1 || apiPort > 65535) {
    return configurationError('EINVOICE_API_URL muss auf den lokalen /api/report/pdf-Endpunkt mit einem gültigen Port zeigen.');
}
