const state = msg.automation;
const candidate = state.candidates[state.candidateIndex];
const status = Number(msg.statusCode || 0);
const responseHeaders = msg.headers && typeof msg.headers === 'object' ? msg.headers : {};
const responseBody = Buffer.isBuffer(msg.payload) ? msg.payload : Buffer.from(msg.payload == null ? '' : String(msg.payload), 'utf8');

function header(name) {
    const key = Object.keys(responseHeaders).find((item) => item.toLowerCase() === name.toLowerCase());
    const value = key ? responseHeaders[key] : undefined;
    return Array.isArray(value) ? String(value[0] || '') : String(value || '');
}
function clearHttpState() {
    delete msg.payload;
    delete msg.headers;
    delete msg.statusCode;
    delete msg.requestTimeout;
    delete msg.followRedirects;
}
function parseRetryAfter(value) {
    const raw = String(value || '').trim();
    if (!raw) return null;
    if (/^\d+$/.test(raw)) {
        const seconds = Number(raw);
        return Number.isFinite(seconds) ? Math.min(seconds * 1000, 600000) : 600000;
    }
    const target = Date.parse(raw);
    if (!Number.isFinite(target)) return null;
    return Math.min(Math.max(target - Date.now(), 0), 600000);
}
function finishCandidate(outcome, detail) {
    state.results.push({ filename: candidate.filename, outcome, ...detail });
    clearHttpState();
    return [msg, null, null];
}
function retry(message) {
    state.retryAfterMs = parseRetryAfter(header('retry-after'));
    state.lastError = message;
    clearHttpState();
    return [null, msg, null];
}
function fail(errorClass, message) {
    msg.automationError = { class: errorClass, message, candidate: candidate.filename, correlationId: state.correlationId, occurredAt: new Date().toISOString() };
    clearHttpState();
    return [null, null, msg];
}

if (status >= 200 && status < 300) {
    const syntax = header('x-einvoice-syntax');
    const validation = header('x-einvoice-validation-status');
    const official = header('x-einvoice-official-status');
    const mediaType = header('content-type').toLowerCase().split(';', 1)[0].trim();
    const hasPdfSignature = responseBody.length >= 5 && responseBody.subarray(0, 5).toString('ascii') === '%PDF-';
    const allowedSyntax = ['CII', 'UBL', 'UNKNOWN'];
    const allowedValidation = ['ok', 'warning', 'invalid'];
    const allowedOfficial = ['accepted', 'rejected', 'not-requested', 'unavailable', 'indeterminate'];
    if (!allowedSyntax.includes(syntax) || !allowedValidation.includes(validation) || !allowedOfficial.includes(official) || mediaType !== 'application/pdf' || !hasPdfSignature) {
        return fail('protocol', 'API-Antwort enthält nicht den vereinbarten PDF- und Statusvertrag.');
    }
    if (syntax === 'UNKNOWN') return finishCandidate('not-supported', { syntax, validation, official });
    if (state.requireKosit && official === 'indeterminate') return retry('KoSIT-Prüfung war technisch unbestimmt.');
    if (state.requireKosit && (official === 'unavailable' || official === 'not-requested')) {
        return fail('configuration', `Verpflichtende KoSIT-Prüfung ist nicht verfügbar (${official}).`);
    }
    const reportNumber = state.reports.length + 1;
    const rawCorrelation = String(state.correlationId || msg._msgid || 'mail');
    const correlationToken = Buffer.from(rawCorrelation, 'utf8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '') || 'bWFpbA';
    state.reports.push({
        filename: `E-Rechnungs-Pruefbericht-${correlationToken}-${reportNumber}.pdf`,
        content: responseBody,
        contentType: 'application/pdf',
        contentDisposition: 'attachment',
        sourceFilename: candidate.filename,
        syntax,
        validation,
        official
    });
    return finishCandidate('processed', { syntax, validation, official });
}

