const state = msg.automation;
delete msg.requestTimeout;
delete msg.followRedirects;
state.candidateIndex += 1;
state.retryCount = 0;
state.retryAfterMs = null;
state.lastError = null;
if (state.candidateIndex < state.candidates.length) return [msg, null];
state.outcome = state.reports.length > 0 ? 'processed' : 'not-supported';
return [null, msg];

const state = msg.automation || {};
const transportDetail = msg.error?.message || msg.error;
if (transportDetail) state.lastError = `HTTP-Verbindungsfehler: ${String(transportDetail).slice(0, 900)}`;
