    const hasServerDelay = state.retryAfterMs !== null && state.retryAfterMs !== undefined;
    const serverDelay = Number(state.retryAfterMs);
    msg.delay = hasServerDelay && Number.isFinite(serverDelay) && serverDelay >= 0 ? Math.min(serverDelay, 600000) : delays[state.retryCount - 1];
    state.retryAfterMs = null;
    return [msg, null];
}
