    class: 'retry-exhausted',
    message: state.lastError || 'Wiederholungen ohne Erfolg ausgeschöpft.',
    candidate: candidate?.filename || null,
    correlationId: state.correlationId || null,
    occurredAt: new Date().toISOString()
};
return [null, msg];

const state = msg.automation || { reports: [], results: [] };
delete msg.requestTimeout;
delete msg.followRedirects;
if (!Array.isArray(state.reports) || state.reports.length === 0) {
    state.outcome = 'not-supported';
    delete msg.payload;
    delete msg.headers;
    return [null, msg, null];
}
