delete msg.headers;
delete msg.statusCode;
delete msg.url;
delete msg.method;
delete msg.requestTimeout;
delete msg.followRedirects;
delete msg.error;
node.status({ fill: 'red', shape: 'ring', text: msg.automationError.class });
